def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    by_subject = {}
    for triple in triples:
        if triple.subject not in by_subject:
            by_subject[triple.subject] = []
        by_subject[triple.subject].append(triple)

    # Build sentences for each subject
    sentences = []
    for subject, subject_triples in by_subject.items():
        parts = []
        for triple in subject_triples:
            pred = triple.predicate
            obj = triple.object

            if pred == 'fullName':
                parts.append(f"{subject}'s full name is {obj}")
            elif pred == 'league':
                parts.append(f"{subject} plays in the {obj}")
            elif pred == 'manager':
                parts.append(f"{subject} is managed by {obj}")
            elif pred == 'season':
                parts.append(f"{subject} competed in the {obj} season")
            elif pred == 'ground':
                parts.append(f"{subject} plays at {obj}")
            elif pred == 'nickname':
                parts.append(f"{subject} is nicknamed {obj}")
            elif pred == 'numberOfMembers':
                parts.append(f"{subject} has {obj} members")
            elif pred == 'owner':
                parts.append(f"{subject} is owned by {obj}")
            elif pred == 'location':
                parts.append(f"{subject} is located in {obj}")
            elif pred == 'country':
                parts.append(f"{subject} is in {obj}")
            elif pred == 'city':
                parts.append(f"{subject} is in {obj}")
            elif pred == 'state':
                parts.append(f"{subject} is in the state of {obj}")
            elif pred == 'champions':
                parts.append(f"{obj} are the champions of {subject}")
            elif pred == 'club':
                parts.append(f"{subject} plays for {obj}")
            elif pred == 'youthclub':
                parts.append(f"{subject} came from {obj}")
            elif pred == 'birthPlace':
                parts.append(f"{subject} was born in {obj}")
            elif pred == 'operator':
                parts.append(f"{subject} is operated by {obj}")
            elif pred == 'tenant':
                parts.append(f"{subject} is tenanted by {obj}")
            elif pred == 'isPartOf':
                parts.append(f"{subject} is part of {obj}")
            elif pred == 'leader':
                parts.append(f"{subject} is led by {obj}")
            elif pred == 'mayor':
                parts.append(f"{subject} is led by mayor {obj}")
            elif pred == 'capital':
                parts.append(f"{subject}'s capital is {obj}")
            elif pred == 'country':
                parts.append(f"{subject} is in {obj}")
            else:
                parts.append(f"{subject}'s {pred} is {obj}")

        if len(parts) > 1:
            sentences.append(", ".join(parts[:-1]) + " and " + parts[-1])
        elif len(parts) == 1:
            sentences.append(parts[0])

    return ". ".join(sentences) + "."

